import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import { useData } from '../context/DataContext';

const LoginForm = () => {
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const { login } = useAuth();
  const { staffList } = useData();
  const navigate = useNavigate();

  const handleSubmit = (e) => {
    e.preventDefault();
    
    // Check Admin cứng (Demo)
    if (username === 'admin' && password === 'admin') {
      login({ username: 'admin', role: 'admin', name: 'Quản trị viên', id: 999 });
      navigate('/admin/staff-manager');
      return;
    }

    // Check Staff từ DataContext
    const staff = staffList.find(s => s.username === username && s.password === password);
    if (staff) {
      login(staff);
      navigate('/staff/attendance');
    } else {
      alert('Sai tên đăng nhập hoặc mật khẩu!');
    }
  };

  return (
    <div style={{ display: 'flex', justifyContent: 'center', marginTop: '50px' }}>
      <form onSubmit={handleSubmit} style={{ padding: '20px', border: '1px solid #ccc', borderRadius: '8px' }}>
        <h2>Đăng nhập Be Able VN</h2>
        <div style={{ marginBottom: '10px' }}>
          <label>Username:</label><br/>
          <input value={username} onChange={e => setUsername(e.target.value)} required />
        </div>
        <div style={{ marginBottom: '10px' }}>
          <label>Password:</label><br/>
          <input type="password" value={password} onChange={e => setPassword(e.target.value)} required />
        </div>
        <button type="submit">Đăng nhập</button>
        <p style={{fontSize: '0.8rem', color: 'gray'}}>Hint: admin/admin hoặc nv1/123</p>
      </form>
    </div>
  );
};

export default LoginForm;
